+async function countLines(filePath: string): Promise<number> {
+  try {
+    const fileStream = fs.createReadStream(filePath);
+    const rl = readline.createInterface({
+      input: fileStream,
+      crlfDelay: Infinity
+    });
+
+    let count = 0;
+    for await (const line of rl) {
+      if (line.trim()) count++;
+    }
+    return count;
+  } catch (error) {
+    return 0; // Return 0 if file can't be read
+  }
+}
